  7	} from '@odf/core/types';
  8	import {
  9	  StorageClassWizardStepExtensionProps as ExternalStorage,
 10	  isStorageClassWizardStep,
 11	} from '@odf/odf-plugin-sdk/extensions';
 12	import { useK8sList } from '@odf/shared';
 13	import { DEFAULT_INFRASTRUCTURE } from '@odf/shared/constants';
 14	import { useK8sGet } from '@odf/shared/hooks/k8s-get-hook';
 15	import {
 16	  CustomResourceDefinitionModel,
 17	  InfrastructureModel,
 18	  NamespaceModel,
 19	  StorageClusterModel,
 20	} from '@odf/shared/models';
 21	import {
 22	  CustomResourceDefinitionKind,
 23	  InfrastructureKind,
 24	} from '@odf/shared/types';
 25	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 26	import { getInfrastructurePlatform } from '@odf/shared/utils';
 27	import {
 28	  useK8sWatchResource,
 29	  useResolvedExtensions,
 30	} from '@openshift-console/dynamic-plugin-sdk';
 31	import * as _ from 'lodash-es';
 32	import { useNavigate, useLocation } from 'react-router-dom-v5-compat';
 33	import { Wizard, WizardStep } from '@patternfly/react-core';
 34	import {
 35	  EmptyState,
 36	  EmptyStateHeader,
 37	  EmptyStateIcon,
 38	  Spinner,
 39	} from '@patternfly/react-core';
 40	import { CREATE_SS_PAGE_URL, Steps, StepsName } from '../../constants';
 41	import { hasAnyExternalOCS, hasAnyInternalOCS } from '../../utils';
 42	import { createSteps } from './create-steps';
 43	import {
 44	  BackingStorage,
 45	  AdvancedSettings,
 46	} from './create-storage-system-steps';
 47	import { EXTERNAL_CEPH_STORAGE } from './external-systems/CreateCephSystem/CephConnectionDetails/system-connection-details';
 48	import { CreateStorageSystemFooter } from './footer';
 49	import { CreateStorageSystemHeader } from './header';
 50	import { initialState, reducer, WizardReducer } from './reducer';
 51	import './create-storage-system.scss';
 52	
 53	const useIsStorageClusterCRDPresent = (): boolean => {
 54	  const [crds, crdsLoaded, crdsError] = useK8sWatchResource<
 55	    CustomResourceDefinitionKind[]
 56	  >({
 57	    groupVersionKind: {
 58	      group: CustomResourceDefinitionModel.apiGroup,
 59	      version: CustomResourceDefinitionModel.apiVersion,
 60	      kind: CustomResourceDefinitionModel.kind,
 61	    },
 62	    isList: true,
 63	    optional: true,
 64	  });
 65	  const storageClusterCRD = crds?.filter(
 66	    (crd) => crd.spec.names.kind === StorageClusterModel.kind
 67	  );
 68	
 69	  const isStorageClusterCRDPresent =
 70	    crdsLoaded && _.isEmpty(crdsError) && storageClusterCRD.length > 0;
 71	
 72	  return isStorageClusterCRDPresent;
 73	};
 74	
 75	const convertModeToDeploymentType = (mode: string): DeploymentType => {
 76	  switch (mode) {
 77	    case StartingPoint.STORAGE_CLUSTER:
 78	      return DeploymentType.FULL;
 79	    case StartingPoint.OBJECT_STORAGE:
 80	      return DeploymentType.MCG;
 81	  }
 82	};
 83	
 84	export const RedirectStorageSystem: React.FC<{}> = () => {
 85	  const navigate = useNavigate();
 86	  const { pathname: url } = useLocation();
 87	
 88	  if (url !== CREATE_SS_PAGE_URL) {
 89	    navigate(CREATE_SS_PAGE_URL, { replace: true });
 90	  }
 91	
 92	  return null;
 93	};
 94	
 95	const CreateStorageSystem: React.FC<{}> = () => {
 96	  const { t } = useCustomTranslation();
 97	  const [state, dispatch] = React.useReducer<WizardReducer>(
 98	    reducer,
 99	    initialState
100	  );
101	  const location = useLocation();
102	
103	  React.useEffect(() => {
104	    // To set up deployment type based the URL
105	    const urlParams = new URLSearchParams(location.search);
106	    const mode = urlParams.get('mode');
107	    const storageClass = urlParams.get('storageClass');
108	    if (mode) {
109	      dispatch({
110	        type: 'backingStorage/setDeployment',
111	        payload: convertModeToDeploymentType(mode),
112	      });
113	    }
114	    if (storageClass) {
115	      dispatch({
116	        type: 'wizard/setStorageClass',
117	        payload: { name: storageClass },
118	      });
119	      dispatch({
120	        type: 'backingStorage/setType',
121	        payload: BackingStorageType.EXISTING,
122	      });
123	    }
124	  }, [location.search]);
125	
126	  const [infra, infraLoaded, infraLoadError] = useK8sGet<InfrastructureKind>(
127	    InfrastructureModel,
128	    DEFAULT_INFRASTRUCTURE
129	  );
130	  const [namespaces, namespacesLoaded, namespacesError] =
131	    useK8sList(NamespaceModel);
132	
133	  const [extensions, extensionsResolved] = useResolvedExtensions(
134	    isStorageClassWizardStep
135	  );
136	  const { systemFlags, areFlagsLoaded, flagsLoadError } =
137	    useODFSystemFlagsSelector();
138	
139	  const infraType = getInfrastructurePlatform(infra);
140	
141	  let wizardSteps = [];
142	  let hasOCS: boolean = false;
143	  let hasExternal: boolean = false;
144	  let hasInternal: boolean = false;
145	  let hasMultipleClusters: boolean = false;
146	
147	  const supportedExternalStorage: ExternalStorage[] = React.useMemo(() => {
148	    if (extensionsResolved) {
149	      return [
150	        ...EXTERNAL_CEPH_STORAGE,
151	        ...(extensions?.map(
152	          (vendor) => vendor.properties
153	        ) as ExternalStorage[]),
154	      ];
155	    }
156	    return EXTERNAL_CEPH_STORAGE;
157	  }, [extensions, extensionsResolved]);
158	
159	  const allLoaded = areFlagsLoaded && infraLoaded && namespacesLoaded;
160	  const anyError = flagsLoadError || infraLoadError || namespacesError;
161	
162	  if (allLoaded && !anyError) {
163	    hasExternal = hasAnyExternalOCS(systemFlags);
164	    hasInternal = hasAnyInternalOCS(systemFlags);
165	    hasOCS = hasExternal || hasInternal;
166	    hasMultipleClusters = hasExternal && hasInternal;
167	
168	    wizardSteps = createSteps(
169	      t,
170	      state,
171	      dispatch,
172	      infraType,
173	      hasOCS,
174	      supportedExternalStorage,
175	      hasMultipleClusters
176	    );
177	  }
178	
179	  const steps = [
180	    {
181	      id: 1,
182	      name: StepsName(t)[Steps.BackingStorage],
183	      component: (
184	        <BackingStorage
185	          state={state.backingStorage}
186	          storageClass={state.storageClass}
187	          dispatch={dispatch}
188	          hasOCS={hasOCS}
189	          hasExternal={hasExternal}
190	          hasInternal={hasInternal}
191	          stepIdReached={state.stepIdReached}
192	          infraType={infraType}
193	          error={anyError}
194	          loaded={allLoaded}
195	          supportedExternalStorage={supportedExternalStorage}
196	        />
197	      ),
198	      canJumpTo: true,
199	    },
200	    {
201	      id: 2,
202	      name: StepsName(t)[Steps.AdvancedSettings],
203	      component: (
204	        <AdvancedSettings
205	          state={state.advancedSettings}
206	          dispatch={dispatch}
207	          hasOCS={hasOCS}
208	          hasMultipleClusters={hasMultipleClusters}
209	          deployment={state.backingStorage.deployment}
210	          backingStorageType={state.backingStorage.type}
211	        />
212	      ),
213	      canJumpTo: true,
214	    },
215	    ...wizardSteps,
216	  ];
217	
218	  return (
219	    <>
220	      <CreateStorageSystemHeader state={state} />
221	      <Wizard
222	        className="odf-create-storage-system-wizard"
223	        isVisitRequired
224	        footer={
225	          <CreateStorageSystemFooter
226	            state={state}
227	            hasOCS={hasOCS}
228	            dispatch={dispatch}
229	            disableNext={!allLoaded || !!anyError}
230	            supportedExternalStorage={supportedExternalStorage}
231	            existingNamespaces={namespaces}
232	          />
233	        }
234	      >
235	        {steps.map((step) => (
236	          <WizardStep key={step.id} id={step.id} name={step.name}>
237	            {step.component}
238	          </WizardStep>
239	        ))}
240	      </Wizard>
241	    </>
242	  );
243	};
