245	const CreateStorageSystemWtihLoader: React.FC = () => {
246	  const { t } = useCustomTranslation();
247	  // In case it randomly goes loading or refetches
248	  const [isCrdPresent, setIsCrdPresent] = React.useState(false);
249	  const isStorageClusterCRDPresent = useIsStorageClusterCRDPresent();
250	  // It takes a while for the CRD to be present
251	  const [delayedShow, setDelayedShow] = React.useState(false);
252	
253	  React.useEffect(() => {
254	    if (isStorageClusterCRDPresent && !isCrdPresent) {
255	      setIsCrdPresent(true);
256	    }
257	  }, [isCrdPresent, isStorageClusterCRDPresent]);
258	
259	  React.useEffect(() => {
260	    let timer: NodeJS.Timeout;
261	
262	    if (isCrdPresent) {
263	      timer = setTimeout(() => setDelayedShow(true), 5000);
264	    }
265	
266	    return () => clearTimeout(timer);
267	  }, [isCrdPresent]);
268	
269	  return !isCrdPresent || !delayedShow ? (
270	    <>
271	      <CreateStorageSystemHeader state={{} as any} />
272	      <EmptyState
273	        className="odf-create-storage-system-wizard__empty-state"
274	        data-test="create-wizard-empty-state"
275	      >
276	        <EmptyStateHeader icon={<EmptyStateIcon icon={Spinner} />} />
277	        <p>
278	          {t(
279	            'Data Foundation is gathering required resources, this may take up to a minute.'
280	          )}
281	        </p>
282	      </EmptyState>
283	    </>
284	  ) : (
285	    <CreateStorageSystem />
286	  );
287	};
288	
289	export default CreateStorageSystemWtihLoader;

